import React from 'react';

const CHOICE_TYPES = {
  radio: 'radio',
  checkbox: 'checkbox',
};

let nextChoiceGroupId = 1;

// function arrayToDict(array) {
//   if (!Array.isArray(array)) {
//     return { array };
//   }
//   const dict = {};
//   for (let i = 0; i < array.length; i++) {
//     const value = array[i];
//     dict[value] = value;
//   }
//   return dict;
// }

export default React.createClass({
  propTypes: {
    type: React.PropTypes.string,
    choices: React.PropTypes.array,
    value: React.PropTypes.array,
  },
  getDefaultProps() {
    return {
      type: CHOICE_TYPES.radio,
      choices: [],
      value: [],
    };
  },
  getValue() {
    const values = [];
    Object.keys(this.refs).forEach(ref => {
      const refEl = this.refs[ref];
      if (refEl.checked) {
        values.push(refEl.value);
      }
    });
    return values;
  },
  renderChoices() {
    // const initialValues = arrayToDict(this.props.value);
    const type = CHOICE_TYPES[this.props.type] || CHOICE_TYPES.radio;
    const choicesName = `fc${nextChoiceGroupId}`;
    return this.props.choices.map((choice, i) => {
      const value = choice[0];
      const label = choice[1] || value;
      const checked = this.props.value.indexOf(value) > -1;
      const htmlFor = `${choicesName}${i}`;
      return (
        <div key={i} className={`facet-${type}`}>
          <label htmlFor={htmlFor} className={`facet-${type}__label`}>
            <input id={htmlFor} ref={`item${i}`}
              name={choicesName}
              value={value}
              className={`facet-${type}__input`}
              type={type} defaultChecked={checked}
            />{label}
          </label>
        </div>
      );
    });
  },
  render() {
    nextChoiceGroupId++;
    return (
      <div className="facet-choice">
        {this.renderChoices()}
      </div>
    );
  },
});



