function getDistance(data) {
  return `${data.distance || 0}`;
}

function getFirstPrice(data) {
  return `${data.firstPrice || 0}`;
}

function getLastPrice(data) {
  return `${data.lastPrice || 0}`;
}

function getLikes(data) {
  return data.likes || 0;
}

function getMaxPrice(data) {
  return data.maxPrice || 0;
}

function getMinPrice(data) {
  return data.minPrice || 0;
}

function getProductImage(data, NO_IMG_SRC, ASSETS_PREFIX) {
  let src = (data.product || {}).imageSrc || NO_IMG_SRC;
  if (src.startsWith('assets')) {
    src = ASSETS_PREFIX + src;
  }
  return src;
}

function getProductName(data) {
  return (data.product || {}).name || 'Нет названия';
}

export default {
  getDistance,
  getFirstPrice,
  getLastPrice,
  getLikes,
  getMaxPrice,
  getMinPrice,
  getProductImage,
  getProductName,
};



