function queryToMongoQuery(queryDict = {}) {
  const where = {};
  if (Array.isArray(queryDict.price) && queryDict.price.length === 2) {
    const pricePart = { };
    const fromPrice = Number.parseFloat(queryDict.price[0]);
    const toPrice = Number.parseFloat(queryDict.price[1]);
    if (fromPrice) {
      pricePart['>='] = fromPrice;
    }
    if (toPrice) {
      pricePart['<='] = toPrice;
    }
    where.lastPrice = pricePart;
  }
  return where;
}

export default {
  queryToMongoQuery,
};



