import React from 'react';
import utils from './utils';
const NO_IMG_SRC = 'https://upload.wikimedia.org/wikipedia/ru/a/ac/No_image_available.svg';
const ASSETS_PREFIX = 'https://offerist.herokuapp.com/';

export default React.createClass({
  propTypes: {
    data: React.PropTypes.object,
    onClick: React.PropTypes.func,
    onAddClick: React.PropTypes.func,
  },
  getDefaultProps() {
    return {
      data: {},
    };
  },
  handleClick(event) {
    if (this.props.onClick) {
      this.props.onClick(this.props.data, event);
    }
  },
  handleAddClick(event) {
    if (this.props.onClick) {
      this.props.onClick(this.props.data, event);
    }
  },
  render() {
    const data = this.props.data;
    return (
      <div className="product-item product-item_result"
        onClick={this.handleClick}
      >
        <img className="product-item__img"
          src={utils.getProductImage(data, NO_IMG_SRC, ASSETS_PREFIX)}
        />
        <div className="product-item__price-header">
          <div className="arrow-left"></div>
          <div className="circle"></div>
          <span className="product-item__price-header_through">
            <span>{utils.getFirstPrice(data)}</span>
            <span>р.</span>
          </span>
          <span>{utils.getLastPrice(data)}</span>
          <span>р.</span>
        </div>
        <div className="product-item__like">
          <i className="fa fa-thumbs-up"></i><span>{utils.getLikes(data)}</span>
        </div>
        <div className="product-item__dist">
          <i className="fa fa-map-marker"></i>
          <span>{utils.getDistance(data)}</span>
          <span>км</span>
        </div>
        <div className="product-item__price-footer">
          <div className="arrow-left"></div>
          <div className="circle"></div>
          <span>{'от '}</span>
          <span>{utils.getMinPrice(data)}</span>
          <span>{' до '}</span>
          <span>{utils.getMaxPrice(data)}</span>
          <span>{' р.'}</span>
        </div>
        <div className="product-item__add"
          onClick={this.handleAddClick}
        >
          <i className="fa fa-plus"></i>
        </div>
        <h3 className="product-item__title">{utils.getProductName(data)}</h3>
      </div>
    );
  },
});



