import React from 'react';
import Facet from '../../components/Facet';
import FacetRange from '../../components/FacetRange';
import FacetChoice from '../../components/FacetChoice';

const INPUT_TYPES = {
  choice(params = {}) {
    const type = params.multiple ? 'checkbox' : 'radio';
    return (
      <FacetChoice type={type} choices={params.choices} value={params.value} />
    );
  },
  range(params = {}) {
    return (
      <FacetRange fromLabel={params.fromLabel} toLabel={params.toLabel} value={params.value} />
    );
  },
};


export default function buildFacets(schema = []) {
  const facets = [];
  schema.forEach((facetSchema, i) => {
    let input = null;
    const inputBuilder = INPUT_TYPES[facetSchema.input];
    if (inputBuilder) {
      input = inputBuilder(facetSchema.inputParams);
    } else {
      console.warn(`Facet input type ${facetSchema.input} not registered`);
    }
    if (input) {
      facets.push(
        <Facet ref={`facet${i}`} key={facetSchema.name}
          name={facetSchema.name}
          title={facetSchema.title}
          open={facetSchema.open}
          openable={facetSchema.openable}
          type={facetSchema.type}
        >{input}</Facet>
      );
    }
  });
  return facets;
}



