import React from 'react';
import buildFacets from './builder';
import backend from '../../api/backend';

export default React.createClass({
  propTypes: {
    schema: React.PropTypes.string,
    onChange: React.PropTypes.func,
  },
  getInitialState() {
    return {
      schema: [],
      loaded: false,
      error: false,
    };
  },
  componentDidMount() {
    this.loadFilters();
  },
  getValue() {
    const values = {};
    Object.keys(this.refs).forEach(ref => {
      const child = this.refs[ref];
      if (child.getValue && child.getName) {
        const name = child.getName();
        const value = child.getValue();
        values[name] = value;
      }
    });
    return values;
  },
  loadFilters() {
    let error = false;
    let schema = [];
    backend.loadFilters(this.props.schema).then(data => {
      schema = data;
    }).catch(err => {
      error = true;
      console.error('Error while load filter schema', err);
    }).then(() => {
      this.setState({
        loaded: true,
        error,
        schema,
      });
    });
  },
  handleFilterBtnClick() {
    if (this.props.onChange) {
      this.props.onChange(this.getValue());
    }
  },
  renderFacets() {
    const facets = buildFacets(this.state.schema);
    return (
      <div key="facets">
        {facets}
        <div className="facet__controls">
          <button
            className="facet__btn-show"
            onClick={this.handleFilterBtnClick}
          >Применить</button>
        </div>
      </div>
    );
  },
  renderError() {
    return (
      <div key="error">Ошибка при загрузке фильтров</div>
    );
  },
  renderLoader() {
    return (
      <div key="loader">Загрузка фильтров</div>
    );
  },
  render() {
    let result = null;
    if (!this.state.loaded) {
      result = this.renderLoader();
    } else if (this.state.error) {
      result = this.renderError();
    } else {
      result = this.renderFacets();
    }
    return (
      <div className="facets facet-wrapper">{result}</div>
    );
  },
});



