import React from 'react';
import Toolbar from '../Toolbar';
import ProductItem from '../ProductItem';
import Facets from '../Facets';


import backend from '../../api/backend';
import utils from './utils';

let resultCount = 1;

export default React.createClass({
  getInitialState() {
    return {
      items: [],
      loaded: false,
      error: false,
    };
  },
  componentDidMount() {
    this.searchParams = {
      query: {},
      sort: {},
    };
    this.search();
  },
  search() {
    this.setState({
      loaded: false,
    });
    let items = [];
    let error = false;

    const where = utils.queryToMongoQuery(this.searchParams.query);

    backend.shopItem(where).then(data => {
      if (Array.isArray(data)) {
        items = data;
      }
    }).catch(err => {
      console.error(err);
      error = true;
    }).then(() => {
      this.setState({
        items,
        error,
        loaded: true,
      });
    });
  },
  handleFacetChange(value) {
    this.searchParams.query = value;
    this.searchParams.sort = {};
    this.search();
  },
  handleToolbarItemClick(params) {
    this.searchParams.sort = params;
    this.search();
  },
  renderLoader() {
    if (this.state.loaded) {
      return null;
    }
    return (
      <div key="loader" className="loader">
        <div className="spinner">
        </div>
      </div>
    );
  },
  renderError() {
    return (
      <div key="error">Ошибка при запросе!</div>
    );
  },
  renderItems() {
    const items = this.state.items.map(itemData =>
      <ProductItem key={itemData.id} data={itemData} />
    );
    return (
      <div key={`results${resultCount++}`}>
        {items}
      </div>
    );
  },
  render() {
    let resultContent = null;
    if (this.state.error) {
      resultContent = this.renderError();
    } else {
      resultContent = this.renderItems();
    }
    return (
      <div className="product-search">
        <Toolbar onItemClick={this.handleToolbarItemClick} />
        <div className="product-search__facet">
          <Facets onChange={this.handleFacetChange} schema="any" />
        </div>
        <div className="product-search__result">
          {this.renderLoader()}
          {resultContent}
        </div>
      </div>
    );
  },
});



