import React from 'react';
import ToolbarBtn from './ToolbarBtn';

export default React.createClass({
  propTypes: {
    title: React.PropTypes.string,
    opened: React.PropTypes.bool,
    openable: React.PropTypes.bool,
    children: React.PropTypes.array,
    onItemClick: React.PropTypes.func,
  },
  getDefaultProps() {
    return {
      title: '',
      opened: true,
      openable: true,
    };
  },
  handleBtnClick(params, event) {
    if (this.props.onItemClick) {
      this.props.onItemClick(params, event);
    }
  },
  render() {
    return (
      <div className="toolbar">
        <label className="toolbar__title">Поблизости</label>
        <ToolbarBtn
          onClick={this.handleBtnClick}
          name="distance"
          value="200"
        >до 200 м</ToolbarBtn>
        <ToolbarBtn
          onClick={this.handleBtnClick}
          name="distance"
          value="500"
        >до 500 м</ToolbarBtn>
        <ToolbarBtn
          onClick={this.handleBtnClick}
          name="distance"
          value="1000"
        >до 1 км</ToolbarBtn>
        <ToolbarBtn
          onClick={this.handleBtnClick}
          name="onMap"
        >на карте</ToolbarBtn>
        <label className="toolbar__title">Сортировать по</label>
        <ToolbarBtn
          onClick={this.handleBtnClick}
          name="sort"
          value="price"
        >цене</ToolbarBtn>
        <ToolbarBtn
          onClick={this.handleBtnClick}
          name="sort"
          value="popularity"
        >популярности</ToolbarBtn>
      </div>
    );
  },
});



