import React from 'react';


export default React.createClass({
  propTypes: {
    fromLabel: React.PropTypes.string,
    toLabel: React.PropTypes.string,
    value: React.PropTypes.array,
  },
  getDefaultProps() {
    return {
      value: [],
    };
  },
  getValue() {
    return [
      this.refs.from.value || '',
      this.refs.to.value || '',
    ];
  },
  render() {
    const [defaultFrom = '', defaultTo = ''] = this.props.value;
    return (
      <div className="facet-range">
        <div className="facet-range__group">
          <input ref="from"
            defaultValue={defaultFrom}
            className="facet-range__group-input"
            type="text"
            placeholder="От"
          />
          <input ref="to"
            defaultValue={defaultTo}
            className="facet-range__group-input"
            type="text" placeholder="До"
          />
        </div>
      </div>
    );
  },
});



